mapper.select:
SELECT t.* FROM pp_task t WHERE t.totalNumber > t.compatedNumber + ( SELECT COUNT(*) FROM pp_task_claim c WHERE c.taskId = t.id AND c.leaseExpireTime > NOW() ) AND NOT EXISTS ( SELECT 1 FROM pp_task_claim c WHERE c.taskId = t.id AND c.deviceId = #{deviceId} )
AND t.roomId = #{roomId}
ORDER BY t.id LIMIT 1 FOR UPDATE
